property.description:
상단 header의 오른쪽 영역에 적용할 class명.
  기본적으로 background 속성에 image의 url이 적용되어있으므로 image를 제거하고자 할 때는 background-image:none;을 적용해야한다.
/**

grandTotalVals의 name을 변경할 수 있는 formatter
 |(예시)
 |<w2:pivot id="pivot1" grandTotalValsNameFormatter="scwin.pivot1_grandTotalValsNameFormatter">
 | scwin.pivot1_grandTotalValsNameFormatter = function(colId) {
 |     if (colId === "col1") {
 |         return "t_col1";
 |     } else if (colId === "col2") {
 |         return "t_col2"
 |     }
 | };

사용자 정의 데이터 속성. getUserData("userData1") API를 통해 설정한 값을 얻어올 수 있음. 
 | // 속성 값 얻어오기 예시
 | getUserData("userData1");

사용자 정의 데이터 속성. getUserData("userData1") API를 통해 설정한 값을 얻어올 수 있음. 
 | // 속성 값 얻어오기 예시
 | getUserData("userData1");

사용자 정의 데이터 속성. getUserData("userData2") API를 통해 설정한 값을 얻어올 수 있음. 
 | // 속성 값 얻어오기 예시
 | getUserData("userData2");

사용자 정의 데이터 속성. getUserData("userData3") API를 통해 설정한 값을 얻어올 수 있음. 
 | // 속성 값 얻어오기 예시
 | getUserData("userData3");

marker 클릭 시 보여줄 내용을 가져오기 위한 사용자 함수
 사용자 함수는 name 및 code를 인자로 받아 보여줄 문자열을 반환
 |(사용 예시)
 |scwin.mapchart1_contextFormatter = function(name, code) {
 |    return name + "(" + code + ")";
 |}
 |<w2:mapchart id="mapchart1" contextFormatter="scwin.mapchart1_contextFormatter"></w2:mapchart>

 |(관련 속성)
 | useMarker="true"

마커 클릭 시 툴팁 표시 내용을 포맷하는데 사용하는 사용자 정의 함수
 사용자 함수는 markerId를 인자로 받아 다음 객체를 반환: (false 반환시 툴팁을 생성하지 않음)
 |<Object>    object                   툴팁 설정 객체
 |<String>    object.html              툴팁의 HTML 내용
 |<Object>    object.position          마커 중앙 기준 상대 위치
 |<Boolean>   object.moveWithMarker    마커 이동시 툴팁도 함께 이동 (기본값: true)

 |(사용 예시)
 |scwin.mapchart1_tooltipFormatter = function(markerId) {
 |    var markerData = mapchart1.getMarker(markerId);
 |    if (!markerData) return false;
 |    
 |    if (markerId.startsWith("TRAIN_")) {
 |        // 열차인 경우: 마커 위쪽 중앙에 툴팁 표시, 마커 이동시 툴팁도 따라가기
 |        return {
 |            html: "<strong style='color: #2980b9;'>" + markerId + "</strong>",
 |            position: {
 |                x: 2,      // 마커 중앙 기준 X좌표 (오른쪽으로 2px)
 |                y: -35     // 마커 중앙 기준 Y좌표 (위쪽으로 35px)
 |            },
 |            moveWithMarker: true  // 마커 이동시 툴팁도 함께 이동 (기본값이므로 생략 가능)
 |        };
 |    }
 |    return false; // 나머지는 툴팁을 표시하지 않음
 |}
 |<w2:mapchart id="mapchart1" tooltipFormatter="scwin.mapchart1_tooltipFormatter"></w2:mapchart>

tooltip을 보여줄 때, 사용자 정의 string을 가져오기 위한 함수명
 사용자 함수는 name 및 code를 인자로 받아 보여줄 문자열을 반환
 |(사용 예시)
 |scwin.mapchart1_setTooltipStrFunc = function(name, code) {
 |    return name + "(" + code + ")";
 |}
 |<w2:mapchart id="mapchart1" setTooltipStrFunc="scwin.mapchart1_setTooltipStrFunc"></w2:mapchart>

calloutOverlappedLabel="true" 설정시, 콜아웃 처리에서 제외하여 기존 위치에 그대로 보이게 할 지역명을 설정하는 사용자 함수명
 사용자 함수는 지역 코드(code) 또는 지역명(name)의 배열을 반환해야 함
 |(관련 속성)
 | calloutOverlappedLabel="true"

 |(사용 예시)
 |scwin.mapchart1_calloutLabelExceptionHandler = function() {
 |    var exceptionList = ["서울특별시", "충청남도"]; // ["11", "34"] 또는 ["11", "충청남도"]와 같이 code와 name을 혼용하여 작성 가능
 |    return exceptionList;
 |}
 |<w2:mapchart id="mapchart1" calloutOverlappedLabel="true" calloutLabelExceptionHandler="scwin.mapchart1_calloutLabelExceptionHandler"></w2:mapchart>

hideOverlappedLabel="true" 설정시, 숨김 처리에서 제외하여 기존 위치에 그대로 보이게 할 지역명을 설정하는 사용자 함수명
 사용자 함수는 지역 코드(code) 또는 지역명(name)의 배열을 반환해야 함
 |(관련 속성)
 | hideOverlappedLabel="true"

 |(사용 예시)
 |scwin.mapchart1_hideLabelExceptionHandler = function() {
 |    var exceptionList = ["서울특별시", "충청남도"]; // ["11", "34"] 또는 ["11", "충청남도"]와 같이 code와 name을 혼용하여 작성 가능
 |    return exceptionList;
 |}
 |<w2:mapchart id="mapchart1" hideOverlappedLabel="true" hideLabelExceptionHandler="scwin.mapchart1_hideLabelExceptionHandler"></w2:mapchart>

[default:true, false] XML 조회 API 호출 시 반환하는 XML에 행의 상태값이 갱신에서 제거로 바뀐 데이터를 포함할지 여부
 (갱신에서 제거로 바뀐 대표적인 경우는 insertRow 후 removeRow한 경우)
 saveRemovedData 속성이 true일 때만 유효
 removeDummyRowStatus 값이 true인 경우는 insertRow했다가 removeRow한 데이터는 관리하지 않음
 |(옵션 설명)
 |"true" (기본 값) : 갱신(C)에서 제거(E)로 바뀐 데이터를 포함하지 않음
 |"false" : 갱신(C)에서 제거(E)로 바뀐 데이터를 포함

 |(관련 함수)
 | getModifiedXML();
 | getDeletedXML();
 | getVoidXML();
 | getOnlyDeletedXMLAPI();

[default:true, false] XML 조회 API 호출 시 반환되는 XML의 구조가 제거 상태인 것을 별도 구조로 할지에 대한 옵션
 구 버전 엔진의 하위 호환을 위해 만든 옵션이므로 true로 설정하고 사용
 |(옵션 설명)
 |"true" (기본 값) : 제거(상태값: E)된 것을 별도의 구조로 구성하지 않음
 |"false" : 제거된 것을 별도의 구조로 구성

 |(관련 함수)
 | getModifiedXML();
 | getDeletedXML();
 | getVoidXML();
 | getOnlyDeletedXMLAPI();

[default:false, true] Match 정보의 조회 시, 대소문자 구별 여부
 |(옵션 설명)
 |"true" : 대소문자를 구분하지 않음
 |"false" (기본 값) : 대소문자를 구분

 |(관련 함수)
 | getMatchedArray();
 | getMatchedColumnData();
 | getMatchedData();
 | getMatchedIndex();
 | getMatchedJSON();
 | getMatchedXML();

[default:false, true] Match 정보의 조회 시, 데이터 비교 방법 설정
 |(옵션 설명)
 | "true" : GridView에 useFilter="true" 설정으로 필터가 적용된 경우에도, 필터링된 데이터가 아니라 전체 데이터를 기준으로 비교
 | "false" (기본 값) : 필터링된 데이터를 기준으로 비교

 |(관련 함수)
 | getMatchedIndex();
 | getMatchedData();
 | getMatchedArray();
 | getMatchedJSON():
 | getMatchedXML();

컬럼 속성이 nullYN인 컬럼에서 공백 값에 대한 처리를 지정하는 속성
 |(옵션 설명)
 | default (기본 값) : data를 조회하는 API(아래의 관련 함수)의 결과값이 기존과 동일하게 동작함.
 | exclude : data를 조회하는 API 호출 시 nullYN="true"인 컬럼에 대해 공백 값은 키에서 제외하고 값을 반환함.
 | null : data를 조회하는 API 호출 시 nullYN="true"인 컬럼에 대해 공백 값을 null로 변경하여 반환함.
 |(관련 함수)
 | $p.data.get("JSON");
 | dataList1.getAllJSON();
 | dataList1.getInsertedJSON();
 | dataList1.getUpdatedJSON():
 | dataList1.getModifiedJSON();
 | dataList1.getOnlyDeletedJSON();
 |(관련 속성)
 | dataList column의 nullYn 속성값. 이 속성값이 true인 컬럼에 대해서만 이 설정이 동작한다.

사용자 정의 데이터 속성
 API를 통해 설정한 값을 얻어올 수 있음
 |(관련 함수)
 | getUserData();

 | // 속성 값 얻어오기 예시
 | getUserData("userData1");

사용자 정의 데이터 속성
 API를 통해 설정한 값을 얻어올 수 있음
 |(관련 함수)
 | getUserData();

 | // 속성 값 얻어오기 예시
 | getUserData("userData2");

사용자 정의 데이터 속성
 API를 통해 설정한 값을 얻어올 수 있음
 |(관련 함수)
 | getUserData();

 | // 속성 값 얻어오기 예시
 | getUserData("userData3");

새로운 행이 추가된 후에 발생 (여러 행이 동시에 추가되면 한번만 발생)
 |(관련 함수)
 | insertRow();
 | insertData();
 | insertJSON();
 | insertXML();

 |(참고 사항)
 |setJSON과 같은 API를 append 모드로 호출하는 경우 해당 이벤트는 발생하지 않고 ondataload 이벤트가 호출됨
 |(append 모드로 데이터가 추가되는 것은 insertRow와 다르게 취급됨)

행이 제거된 후에 발생 (여러 행이 동시에 제거되면 한번만 발생)
 |(관련 함수)
 | removeRow();
 | removeRows();
 | removeRange();
 | removeAll();

 |(참고 사항)
 |setJSON API에 의해 데이터 전체가 변경되는 경우 해당 이벤트는 발생하지 않고 ondataload 이벤트가 호출됨
 |deleteRow API와 같이 행이 제거되지 않고 행의 상태만 변경되는 API 호출 시에도 해당 이벤트는 발생하지 않음

[default:false, true] column에서 data의 공백 값을 특수 처리할 때 사용하는 속성. 공백 값을 dataList의 nullYnType에 따라 처리한다.
 |(옵션 설명)
 | "true" : column의 data가 공백인 값을 null로 취급한다. 
 | "false" (기본 값) : column의 data에 null을 허용하지 않는다. null 또는 undefined인 값은 공백으로 자동 치환된다.
 |(관련 속성)
 | dataList의 nullYnType 값. 
 | nullYnType = "default" : 공백 값을 빈 값으로 처리. data를 조회하는 API(아래 관련 함수) 호출 시 결과값이 기존과 동일하게 동작한다.
 | nullYnType = "exclude" : 공백 값을 키에 포함시키지 않음. data를 조회하는 API 호출 시 결과값에서 공백인 값인 컬럼이 제외된다.
 | nullYnType = "null" : 공백 값을 null로 처리. data를 조회하는 API 호출 시 결과값에서 공백이 null로 치환된다.
 |(관련 함수)
 | $p.data.get("JSON");
 | dataList1.getAllJSON();
 | dataList1.getInsertedJSON();
 | dataList1.getUpdatedJSON():
 | dataList1.getModifiedJSON();
 | dataList1.getOnlyDeletedJSON();

렌더링 완료 후 호출되는 포맷터 함수 (usePageList="true"인 경우 새로운 페이지 로드 시마다 호출)
 뷰 모드(PC View, Mobile View)에 따른 스타일 등 변경을 할 수 있음
 |(함수 설명)
 | 매개변수 info
 |  info.mode : "mobile" 또는 "pc"
 |  info.rows : 모든 행 정보 배열 [{elementId, rowIndex, viewIndex}, ...]
 |    - elementId: row 최상위 컴포넌트 ID
 |    - rowIndex: DataList 기준 실제 행 인덱스
 |    - viewIndex: 화면에 표시되는 행 인덱스 (0부터 시작)

 |(사용 예시)
 |scwin.listView1_adaptiveFormatter = function(info) {
 |    var mode = info.mode;
 |    if (mode === "mobile") {
 |        for (var i = 0; i < info.rows.length; i++) {
 |            var row = info.rows[i];
 |            var rowElement = $p.getComponentById(row.elementId).render;
 |            rowElement.firstChild.style.borderBottom = "1px solid #ccc";
 |        }
 |    }
 |};
 |<w2:listView id="listView1" ... adaptiveFormatter="scwin.listView1_adaptiveFormatter" ...>

[default: false, true] 삭제된 행을 화면에서 보여지지 않게 할지 여부 
 (단, groupby나 drilldown에서는 미지원)
 |(관련 함수)
 | deleteRow();
 | deleteRows();

[default: false, true] 부분합과 푸터 등에서 삭제된 행을 제외하고 계산을 실행 
 |(관련 함수)
 | deleteRow();
 | deleteRows();

[default: ""] Ctrl(또는 cmd)+C 또는 Ctrl(또는 cmd)+X를 통해 데이터를 클립보드에 복사하는 동작을 방지할 컬럼의 아이디를 지정 (셀이 편집모드인 경우에는 설정이 무시됨)
 |(사용 예시) 
 | preventCopyColumn = "col1,col2";

[default: ""] Ctrl(또는 cmd)+V를 통해 클립보드의 정보를 붙여넣는 동작을 방지할 컬럼의 아이디를 지정 (셀이 편집모드인 경우에는 설정이 무시됨)
 |(사용 예시) 
 | preventPasteColumn = "col1,col2";

부분합의 값에 따른 스타일의 적용을 해주는 사용자 함수를 지정
 |(함수 설명)
 | 매개변수 value, formattedValue, subtotalColumnId
 |  value : 원본 데이터
 |  formattedValue : 형태가 적용된 데이터
 |  subtotalColumnId : 부분합 컬럼명

 |(사용 예시)
 | //부분합 값이 음수일 때는 파란색, 양수일 때는 빨간색으로 표헌하고자 하는 경우
 | // 먼저 다음과 같이 css를 등록 : .cm_subtotalplus{color:red;} .cm_subtotalminus{color:blue;}
 | scwin.gridView1_subtotalStyleFormatter = function(value, formattedValue, subtotalColumnId) {
 |    if (subtotalColumnId !== "column28" && subtotalColumnId !== "column23") {
 |        return;
 |    }
 |    if (isNaN(value) || value === 0) {
 |        return;
 |    }
 |    if (value > 0) { 
 |        return "cm_subtotalplus";
 |    } else if (value < 0) { 
 |        return "cm_subtotalminus";
 |    }
 |}

inputType이 "image" 혹은 "textimage"인 경우 셀 클릭 시 실행할 함수
 |(함수 설명)
 | 매개변수는 rowIndex, colId, nowValue로 구성

 (사용 예)
  <w2:column id="col1" inputType="textImage"
  imageClickFunction="scwin.gridView_imageClickFunc"/>

  <script type="text/javascript" lazy="false"><![CDATA[
  scwin.gridView_imageClickFunc = function(rowIndex, colId, nowValue){
       alert('image clicked!');
  }
  ]]>

유효성 검증 결과가 실패일 경우, 결과 메시지를 동적으로 표시할 사용자 정의 함수 이름 (inputType = "calendar", dateValidCheck = "true", dateValidSetCustom = "true"일 경우만 유효)
|// (사용자 정의 함수 예) |// 유효하지 않은 날짜 형식의 값이 입력될 경우 사용자 팝업인 messagePopup.xml을 띄우고, 이전 값으로 복귀하는 예시 | |scwin.gridView1_col1_invalidMessageFunc = function() { | var opts = { | "id" : "popup1", | "type" : "wframePopup", | "width" : "440px", | "height" : "90px", | "top" : 100, | "left" : 300, | "popupName" : "date_validation_error", | "modal" : true, | "title" : "date validation error", | "dataObject" : { | "type" : "string", | "data" : this.callerId, | "name" : "callerId" | } | }; | if (!$p.getPopup("popup1")) { | $p.openPopup("messagePopup.xml", opts); | } |}
|(관련 속성) | inputType = "calendar" | dateValidCheck = "true" | dateValidSet = "true" | dateValidSetCustom = "true"

customFormatter와 동작은 거의 동일하나 사용 목적이 <script> 태그와 같은 보안상 이슈가 발생하는 문자열을 직접 제어하기 위함 (Formatter 중 가장 먼저 적용)
  inputType이 "text"인 경우에만 유효
 |(함수 설명)
 | 문자열을 직접 제어하기 위함 Formatter 함수
 | 매개변수는 data, rowIndex, colIndex로 구성

 |(사용 예)
 |전역 스크립트에 아래를 정의한 후, 해당 속성에 "fn_escapeFormat"를 지정
 | function fn_escapeFormat (tmpVal, rowIndex, colIndex){ 
 |                   var colId = this.getColumnID(colIndex); 
 |                   if(colId == "xxx"){ 
 |                           return tmpVal.replace(/<script.*script>/g, "") 
 |                           } 
 |                   };

inputType이 "custom"인 경우 셀의 타입을 동적으로 설정하기 위한 함수 (drilldown 미지원)
 |(함수 설명)
 | 셀에 표현할 inputType에 대한 정보 동적으로 구성
 | 매개변수 : colID, colIndex, rowIndex, realRowIndex가 포함된 JSON 객체로 구성 

 |(사용 예)
 | <w2:column id="col1" inputType="custom" typeGetter="scwin.gridView1_getType"></w2:column>
 | 
 | scwin.gridView1_getType = function(info) { 
 |    var rowIndex = info.rowIndex;
 |    var colIndex = info.colIndex;
 |    var returnInfo;
 |    var inputType = inputTypeDataList.getCellData( rowIndex, colIndex );
 |    
 |    switch(inputType) {
 |        case "select": 
 |            returnInfo = {
 |                id : "dynamic_select_" + rowIndex + "_" + colIndex,
 |                inputType : "select",
 |                options : {viewType: "icon", textAlign : "left", displayMode : "value"},
 |                itemSet : {
 |                    nodeset: "data:dataList1", 
 |                    label: "label",
 |                    value: "value"
 |                }
 |            }
 |            break;
 |        case "text": 
 |            returnInfo = {
 |                id : "dynamic_text_" + rowIndex + "_" + colIndex,
 |                inputType : "text",
 |                options : {}
 |            }
 |            break;
 |    }
 |    
 |    return returnInfo;
 | }

입력이 가능한 컬럼에서 포커스가 빠져나가는 시점에 본 속성에 정의한 함수를 실행
 엑셀수식을 동일하게 사용할 수 있으며, 컬럼명을 설정하게 되면 다운로드시 엑셀좌표값으로 변경하여 적용
 |(사용 예)
 | function fn_idValid(tmpVal){ // tmpVal는 셀이 가진 값임
 |     return tempVal + "$$"; 
 | } };

validate API의 검증 결과가 실패일 경우, 결과 메시지를 동적으로 표시할 사용자 정의 함수 이름. 
 displaymessage="true"일 경우만 유효. invalidMessage와 동시 적용 불가. 
 |(사용자 정의 함수 예)
 | // 아래 type에 대한 검증 실패 시, 메시지를 동적으로 생성하는 예.
 | // mandatory, allowChar, ignoreChar, minLength, maxLength, minByteLength, maxByteLength
 |
 | function fn_msg(){ 
 |    var tmpType = checkbox1.getType(); 
 |    var tmpValue = checkbox1.getValue(); 
 |    if(tmpType == "mandatory")
 |        { return "필수 검증 항목입니다."; } 
 |    }

  |(관련 API)
  | validate();
  | displaymessage="true"
  | invalidMessage 속성과 동시 적용 불가.

유효성 체크 함수 이름.
 컴포넌트에서 blur가 발생하는 시점에 본 속성에 정의한 함수가 실행됨. 
 즉, onblur 이벤트 이전에 실행되며, blur가 발생하는 시점에 유효성을 확인하며 return을 통해 value를 변경 할 수 있음.
 |(구현 예시)
 | function fn_idValid(tmpVal){ 
 |                        //tmpVal에는 본 컴포넌트의 value값이 담겨있다. 로직 구현후 최종값을 return한다. 
 |                                return tmpVal;
 |                             };

validate(); 검증 결과가 실패일 경우, 결과 메시지를 동적으로 표시할 사용자 정의 함수 이름. 
 invalidMessage 속성과 동시 적용 불가. 
 
 |// (사용자 정의 함수 예)
 |// 아래 type에 대한 검증 실패 시, 메시지를 동적으로 생성하는 예.
 |// mandatory, minlength, minByteLength
 |
 |scwin.fn_msg = function() {
 |    var invalidType = this.getType();  // invalid type 
 |    var invalidValue = this.getValue(); // invalid value
 |    switch (invalidType) {
 |        case "mandatory" :
 |            msg = "Information is required.";
 |            break;
 |        case "minLength" :
 |            msg = "Minimum " + invalidValue + " digits are required.";
 |            break;
 |        case "minByteLength" :
 |            msg = "Minimum " + invalidValue + " bytes are required.";
 |            break;
 |        default :
 |            msg = "Not valid.";
 |            break;
 |    }
 |    return msg;
 |}
 
 |(관련 API)
 | validate();
 | invalidMessage 속성과 동시 적용 불가.

